/**
 * Base URL for public API calls in server components and static export.
 * When `NEXT_PUBLIC_STATIC_EXPORT=1` and `NEXT_PUBLIC_API_BASE_URL` is unset, defaults to
 * production API so `npm run build:frontend:static` can pre-render without a local backend.
 */
export function publicApiBaseUrl(): string {
  const explicit = process.env.NEXT_PUBLIC_API_BASE_URL?.trim();
  if (explicit) return explicit.replace(/\/+$/, '');
  const isStaticExport =
    process.env.NEXT_PUBLIC_STATIC_EXPORT === '1' ||
    process.env.NEXT_PUBLIC_STATIC_EXPORT === 'true';
  if (isStaticExport) return 'https://portalapi.vuleits.com';
  return 'http://127.0.0.1:5000';
}
